const lib = global.get('lib');
if (!lib || !lib.coreControl || typeof lib.coreControl.runUnifiedControlCycle !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'global.lib.coreControl missing' });
  return [null, null, { payload: { error: 'global.lib.coreControl.runUnifiedControlCycle is unavailable' } }];
}

function clone(value) {
  return JSON.parse(JSON.stringify(value));
}

function defaultConfig() {
  return {
    system: { systemProfile: 'eSpire280', controllerTimezone: 'America/Los_Angeles', nominal: { voltageVll: 480, frequencyHz: 60 } },
    network: { controller: { ip: '192.168.1.10', modbusServer: { ip: '192.168.1.20', port: 502 } } },
    operation: { mode: 'grid-tied', gridCode: 'IEEE1547-2018', crdMode: 'no-export', siteExportMode: 'no-restriction', siteExportTargetImportKw: 0, siteExportDeadbandKw: 0, scheduledControlEnabled: false },
    pcs: { pcsDaisyChain: [1, 1], maxChargeKw: 250, maxDischargeKw: 250 },
    mbmu: { sbmuStrings: [2, 2] },
    battery: { minSoc: 0.1, maxSoc: 0.95, socLow: 0.3, socLowRecover: 0.22, socHigh: 0.95, socHighRecover: 0.92, forceGridChargeSoc: 0.15, forceGridChargeMinCellVoltageV: 2.95, forceGridChargeKw: 10, powerHeadroomKw: 2, commandRampKwPerSec: 25 },
    pv: { acInverters: [], curtailmentMethod: null },
    metering: { meterType: 'eGauge-4015', modbusProfile: 'udt_eGauge_V1', ip: '', reads: { pv: true, pvFromInverter: false, utility: true, load: true }, calculations: {} }
  };
}


function normalizeMeteringCalculations(calculations) {
  const out = {};
  for (const [key, value] of Object.entries(calculations || {})) {
    if (typeof value === 'string') {
      out[key] = { source: 'tag', tagID: value };
    } else if (value && typeof value === 'object') {
      out[key] = value;
    }
  }
  return out;
}

function normalizeControlConfig(raw) {
  const defaults = defaultConfig();
  const cfg = clone(raw || defaults);
  cfg.system = Object.assign({}, defaults.system, cfg.system || {});
  cfg.system.nominal = Object.assign({}, defaults.system.nominal, (cfg.system && cfg.system.nominal) || {});
  cfg.operation = Object.assign({}, defaults.operation, cfg.operation || {});
  cfg.battery = Object.assign({}, defaults.battery, cfg.battery || cfg.batteryPolicy || {});
  cfg.pv = Object.assign({}, defaults.pv, cfg.pv || {});
  if (!Array.isArray(cfg.pv.acInverters)) cfg.pv.acInverters = [];
  cfg.metering = Object.assign({}, defaults.metering, cfg.metering || {});
  cfg.metering.reads = Object.assign({}, defaults.metering.reads, cfg.metering.reads || {});
  cfg.metering.calculations = normalizeMeteringCalculations(cfg.metering.calculations || defaults.metering.calculations);
  cfg.network = Object.assign({}, defaults.network, cfg.network || {});
  cfg.network.controller = Object.assign({}, defaults.network.controller, cfg.network.controller || {});
  cfg.network.controller.modbusServer = Object.assign({}, defaults.network.controller.modbusServer, cfg.network.controller.modbusServer || {});
  if (!cfg.network.controller.modbusServer.ip && cfg.metering.ip) cfg.network.controller.modbusServer.ip = cfg.metering.ip;
  if (!cfg.islanding && cfg.protection && cfg.protection.islanding) cfg.islanding = cfg.protection.islanding;
  if (cfg.system.systemProfile && String(cfg.system.systemProfile).startsWith('MINI-')) {
    delete cfg.mbmu;
    if (cfg.pcs && Array.isArray(cfg.pcs.pcsDaisyChain) && cfg.pcs.pcsDaisyChain.length > 0) {
      cfg.pcs = Object.assign({}, cfg.pcs, { pcsDaisyChain: [] });
    }
  }
  global.set('siteConfig', cfg);
  global.set('unifiedControlConfig', cfg);
  return cfg;
}

function defaultSignalMapping() {
  return {
    sources: {
      Meter: { profile: 'udt_eGauge_V1', role: 'siteMeter' },
      Meter2: { profile: 'udt_eGauge_V1', role: 'pvMeter' },
      PCS: { profile: 'Delta_280_ss40k', role: 'pcs' }
    },
    deadbands: { pvKw: 0.3 },
    signals: {
      utilityPowerKw: { expr: 'Meter.Utility_Total_Power', invertSign: false },
      pvKw: { expr: 'deadband(Meter2.Solar, 0.3)', invertSign: false },
      pcsActivePowerKw: { expr: 'PCS.SYSTEM_POWER_ACTIVE_ALL', invertSign: false },
      siteLoadKw: { expr: 'utilityPowerKw + pvKw + pcsActivePowerKw' },
      generatorRunning: { expr: 'Meter.Generator_Total_Power > 1' }
    }
  };
}

function indexTelemetry(telemetry) {
  const index = {};
  const roots = {};
  function put(tagID, value) {
    index[tagID] = value;
    const parts = String(tagID).split('.');
    if (parts.length >= 2) {
      const root = parts.shift();
      const leaf = parts.join('.');
      roots[root] = roots[root] || {};
      roots[root][leaf] = value;
    }
  }
  for (const [key, value] of Object.entries(telemetry || {})) {
    if (Array.isArray(value)) {
      for (const sample of value) {
        if (sample && sample.tagID) put(sample.tagID, sample.value);
      }
    } else if (value && typeof value === 'object' && 'value' in value && value.tagID) {
      put(value.tagID, value.value);
    } else {
      index[key] = value;
      if (key.includes('.')) put(key, value);
    }
  }
  return { index, roots };
}

function numeric(value, fallback) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function firstNumber(index, keys, fallback) {
  for (const key of keys) {
    if (key in index) {
      const n = Number(index[key]);
      if (Number.isFinite(n)) return n;
    }
  }
  return fallback;
}

function activeRealtimeDispatch() {
  const rt = global.get('realtimeDispatch') || flow.get('realtimeDispatch') || {};
  if (rt.enabled === false) return {};
  if (Number.isFinite(Number(rt.expiresAtMs)) && Date.now() > Number(rt.expiresAtMs)) return {};
  return rt;
}

function evalSignal(expr, scope) {
  const deadband = (value, threshold) => Math.abs(Number(value) || 0) < Math.abs(Number(threshold) || 0) ? 0 : Number(value);
  const names = Object.keys(scope).concat(['deadband', 'max', 'min', 'abs', 'round', 'Math']);
  const values = Object.keys(scope).map((name) => scope[name]).concat([deadband, Math.max, Math.min, Math.abs, Math.round, Math]);
  const fn = new Function(...names, '"use strict"; return (' + expr + ');');
  return fn(...values);
}

function buildSchedule(config) {
  const plans = global.get('schedulePlans') || flow.get('schedulePlans');
  if (plans && lib.scheduler && typeof lib.scheduler.matchActiveSchedulePlan === 'function') {
    const activePlan = lib.scheduler.matchActiveSchedulePlan(plans, { now: new Date(), timezone: config.system.controllerTimezone });
    const output = activePlan ? lib.scheduler.scheduleOutputFromActivePlan(activePlan) : {};
    global.set('scheduleOutput', output);
    return output;
  }
  return global.get('scheduleOutput') || flow.get('scheduleOutput') || {};
}

try {
  const rawConfig = msg.controlConfig || flow.get('controlConfig') || global.get('controlConfig') || global.get('unifiedControlConfig') || defaultConfig();
  const config = normalizeControlConfig(rawConfig);
  const signalMapping = config.signalMapping || flow.get('signalMapping') || global.get('signalMapping') || defaultSignalMapping();
  const rawTelemetry = msg.telemetry || (msg.payload && msg.payload.telemetry) || global.get('telemetry') || msg.payload || {};
  const telemetryIndex = indexTelemetry(rawTelemetry);
  const scope = Object.assign({}, telemetryIndex.roots);
  const canonical = {};
  const errors = [];
  const order = ['utilityPowerKw', 'pvKw', 'pcsActivePowerKw', 'siteLoadKw', 'generatorRunning'];

  for (const key of order) {
    const spec = signalMapping.signals && signalMapping.signals[key];
    if (!spec || !spec.expr) continue;
    try {
      const value = evalSignal(spec.expr, Object.assign({}, scope, canonical));
      const finalValue = spec.invertSign ? -Number(value) : value;
      canonical[key] = typeof finalValue === 'boolean' ? finalValue : numeric(finalValue, undefined);
    } catch (error) {
      errors.push({ signal: key, expr: spec.expr, error: error.message || String(error) });
    }
  }

  config.metering = config.metering || { meterType: '', modbusProfile: '', ip: '', reads: { pv: true, pvFromInverter: false, utility: true, load: true }, calculations: {} };
  config.metering.calculations = {
    utilityPowerKw: { source: 'tag', tagID: 'utilityPowerKw' },
    siteLoadKw: { source: 'tag', tagID: 'siteLoadKw' },
    pvKw: { source: 'tag', tagID: 'pvKw' }
  };

  const gridStatus = config.operation && config.operation.mode === 'off-grid' ? 'island' : 'normal';
  const realtime = activeRealtimeDispatch();
  const baseTelemetry = {
    soc: firstNumber(telemetryIndex.index, ['MBMU.System_SOC_pct', 'MBMU.system_SOC_raw', 'AMPACE.BamsSOC', 'BMS.SOC', 'soc'], 0.5),
    gridStatus,
    pcsActivePowerKw: canonical.pcsActivePowerKw,
    generatorRunning: canonical.generatorRunning === true,
    realtimeActivePowerKwRequest: numeric(realtime.activePowerKw ?? realtime.realtimeActivePowerKwRequest, undefined),
    realtimeReactivePowerKvarRequest: numeric(realtime.reactivePowerKvar ?? realtime.realtimeReactivePowerKvarRequest, undefined),
    machineStatus: {
      batteryVoltageV: firstNumber(telemetryIndex.index, ['MBMU.System_Voltage_V', 'AMPACE.BamsTotalVol', 'PCS.DCInputVoltage'], undefined),
      maxChargeCurrentAllowedA: firstNumber(telemetryIndex.index, ['MBMU.Max_Charge_Current_Allowed_A', 'AMPACE.BamsPermitChgCurr', 'PCS.MaxChgCurrent'], undefined),
      maxDischargeCurrentAllowedA: firstNumber(telemetryIndex.index, ['MBMU.Max_Discharge_Current_Allowed_A', 'AMPACE.BamsPermitDsgCurr', 'PCS.MaxDsgCurrent'], undefined),
      maxCellVoltageV: firstNumber(telemetryIndex.index, ['MBMU.Max_Cell_Voltage_V', 'AMPACE.BamsMaxCellVol'], undefined),
      minCellVoltageV: firstNumber(telemetryIndex.index, ['MBMU.Min_Cell_Voltage_V', 'AMPACE.BamsMinCellVol'], undefined),
      maxCellTemperatureC: firstNumber(telemetryIndex.index, ['MBMU.Max_Cell_Temperature_C', 'AMPACE.BamsMaxCellTemp'], undefined),
      minCellTemperatureC: firstNumber(telemetryIndex.index, ['MBMU.Min_Cell_Temperature_C', 'AMPACE.BamsMinCellTemp'], undefined),
      bmsStatus: firstNumber(telemetryIndex.index, ['MBMU.BMS_Status', 'AMPACE.BamsStatus'], undefined),
      pcsGlobalState: firstNumber(telemetryIndex.index, ['PCS.SYSTEM_GLOBAL_STATE', 'PCS.SystemStatusMap'], undefined)
    }
  };

  const controlState = flow.get('controlState') || {};
  const cycle = lib.coreControl.runUnifiedControlCycle(config, {
    telemetry: Object.assign({}, telemetryIndex.index, canonical),
    baseTelemetry,
    schedule: buildSchedule(config),
    state: controlState,
    nowMs: Date.now()
  });

  flow.set('controlState', controlState);
  flow.set('lastUnifiedControlCycle', cycle);
  global.set('lastUnifiedControlCycle', cycle);

  const writerMessages = (cycle.writerEnvelopes || []).map((envelope) => ({
    topic: envelope.topic,
    payload: envelope.payload,
    envelope,
    controlCommand: cycle.command
  }));

  node.status({ fill: errors.length ? 'yellow' : 'green', shape: errors.length ? 'ring' : 'dot', text: `${writerMessages.length} writer envelope(s)` });

  return [
    writerMessages,
    { payload: { canonical, realtime, command: cycle.command, pipeline: cycle.pipeline, diagnostics: cycle.diagnostics, writerEnvelopeCount: writerMessages.length, signalMappingErrors: errors } },
    errors.length ? { payload: { errors, canonical } } : null
  ];
} catch (error) {
  node.status({ fill: 'red', shape: 'ring', text: 'control cycle failed' });
  return [null, null, { payload: { error: error.message || String(error), stack: error.stack } }];
}

const cycle = global.get('lastUnifiedControlCycle') || {};
const config = global.get('siteConfig') || global.get('unifiedControlConfig') || global.get('controlConfig') || {};
const groups = global.get('schedulePlans') || flow.get('schedulePlans') || [];
const planCount = Array.isArray(groups) ? groups.reduce((total, group) => total + (Array.isArray(group && group.timed) ? group.timed.length : 0), 0) : 0;
const telemetry = global.get('telemetry') || flow.get('telemetry') || {};
msg.headers = { 'content-type': 'application/json' };
msg.payload = {
  data: {
    ok: true,
    updatedAt: new Date().toISOString(),
    systemProfile: config.system && config.system.systemProfile,
    productLine: cycle.design && cycle.design.productLine,
    operationMode: config.operation && config.operation.mode,
    schedulePlanCount: planCount,
    realtimeDispatch: global.get('realtimeDispatch') || flow.get('realtimeDispatch') || {},
    command: cycle.command || null,
    pipeline: cycle.pipeline || null,
    diagnostics: cycle.diagnostics || null,
    writerEnvelopes: cycle.writerEnvelopes || [],
    telemetryKeys: Object.keys(telemetry).slice(0, 50)
  }
};
return msg;

let body = msg.payload || {};
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch (error) {
    msg.statusCode = 400;
    msg.payload = { error: 'invalid JSON body' };
    return msg;
  }
}
const numberOrUndefined = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : undefined;
};
const ttlSec = Math.max(1, numberOrUndefined(body.ttlSec ?? body.ttlSeconds) || 300);
const dispatch = {
  enabled: body.enabled !== false,
  activePowerKw: numberOrUndefined(body.activePowerKw),
  reactivePowerKvar: numberOrUndefined(body.reactivePowerKvar),
  realtimeActivePowerKwRequest: numberOrUndefined(body.realtimeActivePowerKwRequest ?? body.activePowerKw),
  expiresAtMs: Date.now() + ttlSec * 1000,
  updatedAt: new Date().toISOString(),
  source: body.source || 'api'
};
if (dispatch.enabled === false) {
  dispatch.activePowerKw = undefined;
  dispatch.realtimeActivePowerKwRequest = undefined;
}
global.set('realtimeDispatch', dispatch);
flow.set('realtimeDispatch', dispatch);
msg.headers = { 'content-type': 'application/json' };
msg.payload = { data: dispatch };
return msg;
